const MASK_G26 = `<mask id="g26Mask" maskUnits="userSpaceOnUse"><rect x="100" y="1100" width="1100" height="350" fill="white"/><path fill="black" d="M1029.999,1196.601v115.898c0,7.456,6.045,13.502,13.501,13.502c7.454,0,13.499-6.046,13.499-13.502v-142.896c-0.069,0.069-0.146,0.146-0.213,0.214L1029.999,1196.601z"/><path fill="black" d="M973.999,1215.757v96.22c0,7.456,6.043,13.502,13.5,13.502c7.455,0,13.5-6.046,13.5-13.502v-96.109C992.171,1218.294,982.812,1218.261,973.999,1215.757z"/><path fill="black" d="M917.999,1169.199v143.3c0,7.456,6.045,13.502,13.501,13.502s13.5-6.046,13.5-13.502v-116.302l-26.387-26.385C918.416,1169.615,918.202,1169.402,917.999,1169.199z"/></mask>`;
