// ============================================================================
// CSS Styles for the SVG
// ============================================================================
const SVG_STYLE = `
<style>
  /* Figure background */
  #figure { fill: #f8f8f5; stroke: none; }

  /* Centers - undefined */
  .center-shape { fill: #f5f5f2; stroke: #d0d0d0; stroke-width: 1.5; }
  /* Centers - defined (overridden per center via inline style) */
  .center-shape.defined { stroke: none; }
  .center-highlight { fill: url(#centerDefinedHighlight); opacity: 0; }
  .center-shape.defined + .center-highlight { opacity: 1; }

  /* Channels - inactive */
  .channel { fill: #e0ddd8; opacity: 0.25; }
  /* Channels - active */
  .channel.defined { fill: #222; opacity: 0.55; }

  /* Gate shapes - hidden by default */
  .gate-shape { opacity: 0; }
  .gate-shape.defined { opacity: 1; }
  .gate-shape.c1 use, .gate-shape.c1 path { fill: #000; }
  .gate-shape.c2 use, .gate-shape.c2 path { fill: #D04A49; }
  .gate-shape.mixed use, .gate-shape.mixed path { fill: #6182A0; }

  /* Gate number circles - undefined */
  .gate-num circle { fill: none; stroke: #c0c0c0; stroke-width: 1; }
  .gate-num text { fill: #aaa; font-size: 24px; text-anchor: middle; font-family: Arial, Helvetica, sans-serif; }
  /* Gate number circles - personality (black) */
  .gate-num.defined.c1 circle { fill: #222; stroke: none; }
  .gate-num.defined.c1 text { fill: #fff; }
  /* Gate number circles - design (red) */
  .gate-num.defined.c2 circle { fill: #D04A49; stroke: none; }
  .gate-num.defined.c2 text { fill: #fff; }
  /* Gate number circles - both */
  .gate-num.defined.mixed circle { fill: #6182A0; stroke: none; }
  .gate-num.defined.mixed text { fill: #fff; }

</style>`;

// ============================================================================
// Main SVG Generator
// ============================================================================
function generateBodygraphSvg(result) {
  // Prepare gate lookup sets
  const pGates = new Set();
  const dGates = new Set();
  for (const act of Object.values(result.activations.personality)) {
    pGates.add(act.gate);
  }
  for (const act of Object.values(result.activations.design)) {
    dGates.add(act.gate);
  }
  const activatedGates = new Set(result.activatedGates);
  const activeChannels = new Set(result.channels);
  const definedCenters = new Set(result.definedCenters);

  function gateClass(gate) {
    const inP = pGates.has(gate);
    const inD = dGates.has(gate);
    if (!inP && !inD) return '';
    if (inP && inD) return 'defined mixed';
    if (inD) return 'defined c2';
    return 'defined c1';
  }

  function centerSvgClass(centerName) {
    return definedCenters.has(centerName) ? 'defined' : '';
  }

  let svg = '';

  // SVG header
  svg += `<?xml version="1.0" encoding="utf-8"?>\n`;
  svg += `<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" viewBox="0 0 2000 2000" width="2000" height="2000">\n`;

  // Embedded styles
  svg += SVG_STYLE + '\n';

  // Defs: gradients, masks, gate symbols, center symbols
  svg += `<defs>\n`;

  // Gradients
  svg += `<linearGradient id="centerDefinedBrown" gradientTransform="rotate(90)"><stop offset="0" stop-color="#57423E"/><stop offset="1" stop-color="#57423E"/></linearGradient>\n`;
  svg += `<linearGradient id="centerDefinedRed" gradientTransform="rotate(90)"><stop offset="0" stop-color="#D04A49"/><stop offset="1" stop-color="#D04A49"/></linearGradient>\n`;
  svg += `<linearGradient id="centerDefinedYellow" gradientTransform="rotate(90)"><stop offset="0" stop-color="#FBF7AD"/><stop offset="1" stop-color="#FBF7AD"/></linearGradient>\n`;
  svg += `<linearGradient id="centerDefinedGreen" gradientTransform="rotate(90)"><stop offset="0" stop-color="#669A8D"/><stop offset="1" stop-color="#669A8D"/></linearGradient>\n`;
  svg += `<linearGradient id="centerDefinedHighlight" gradientTransform="rotate(90)"><stop offset="0" stop-color="#FFFFFF" stop-opacity=".15"/><stop offset="1" stop-color="#FFFFFF" stop-opacity="0"/></linearGradient>\n`;

  // Masks
  svg += MASK_G26 + '\n';
  svg += MASK_G34 + '\n';

  // Gate symbols
  for (const [gate, content] of Object.entries(GATE_SYMBOLS)) {
    svg += `<symbol id="sg${gate}">${content}</symbol>\n`;
  }

  // Center symbols
  for (const [id, pathD] of Object.entries(CENTER_SYMBOLS)) {
    svg += `<symbol id="c${id}"><path d="${pathD}"/></symbol>\n`;
  }

  svg += `</defs>\n`;

  // Graph group
  svg += `<g id="graph">\n`;

  // White background
  svg += `<rect width="2000" height="2000" fill="#FFFFFF"/>\n`;

  // Human figure outline
  svg += `<path id="figure" d="${FIGURE_PATH}"/>\n`;

  // ---- Channels ----
  svg += `<g id="channels">\n`;
  for (const [chName, chDef] of Object.entries(CHANNEL_DEFS)) {
    const isActive = activeChannels.has(chName);
    const cls = isActive ? 'channel defined' : 'channel';
    const maskAttr = chDef.mask ? ` mask="${chDef.mask}"` : '';
    if (chDef.elem === 'rect') {
      svg += `<rect ${chDef.d} class="${cls}"${maskAttr}/>\n`;
    } else {
      svg += `<path d="${chDef.d}" class="${cls}"${maskAttr}/>\n`;
    }
  }
  svg += `</g>\n`;

  // ---- Gate shapes (colored segments along channels) ----
  svg += `<g id="gates">\n`;
  for (let gate = 1; gate <= 64; gate++) {
    if (!activatedGates.has(gate)) continue;
    const cls = gateClass(gate);
    if (!cls) continue;
    const maskAttr = gate === 26 ? ' mask="url(#g26Mask)"' : (gate === 34 ? ' mask="url(#g34Mask)"' : '');
    svg += `<g class="gate-shape ${cls}"${maskAttr}>`;
    svg += `<use xlink:href="#sg${gate}"/>`;
    svg += `<use xlink:href="#sg${gate}"/>`;
    svg += `</g>\n`;
  }
  svg += `</g>\n`;

  // ---- Centers with gate numbers ----
  svg += `<g id="centers">\n`;

  for (const [ourName, svgId] of Object.entries(CENTER_SVG_ID)) {
    const isDef = definedCenters.has(ourName);
    const fillStyle = isDef ? ` style="fill:${CENTER_FILL[svgId]}"` : '';
    const shapeClass = isDef ? 'center-shape defined' : 'center-shape';

    svg += `<g id="${svgId}">\n`;

    // Center shape
    svg += `<use xlink:href="#c${svgId}" class="${shapeClass}"${fillStyle}/>\n`;

    // Center highlight (only visible when defined, via CSS)
    const highlights = CENTER_HIGHLIGHTS[svgId];
    if (highlights) {
      for (const hPath of highlights) {
        svg += `<path class="center-highlight${isDef ? ' visible' : ''}" d="${hPath}"${isDef ? ' style="opacity:1"' : ''}/>\n`;
      }
    }

    // Gate numbers
    svg += `<g id="nums">\n`;
    const positions = CENTER_GATE_POSITIONS[svgId];
    if (positions) {
      for (const pos of positions) {
        const gCls = gateClass(pos.gate);
        const numClass = gCls ? `gate-num ${gCls}` : 'gate-num';
        svg += `<g class="${numClass}" transform="translate(${pos.x}, ${pos.y})">`;
        svg += `<circle cx="24" cy="24" r="24"/>`;
        svg += `<text x="24" y="34">${pos.gate}</text>`;
        svg += `</g>\n`;
      }
    }
    svg += `</g>\n`; // nums
    svg += `</g>\n`; // center
  }
  svg += `</g>\n`; // centers

  svg += `</g>\n`; // graph
  svg += `</svg>\n`;
  return svg;
}

module.exports = { generateBodygraphSvg };
